    localparam integer ENGINE_BANK_W = (ENGINE_WGT_W == 4) ? 144 : (32 * ENGINE_WGT_W);
    localparam integer ENGINE_LANE_B = 32 * ENGINE_WGT_W;    // real bits/bank (128|96)
