    // ----- scheduler 'start' one-shot from first accepted input beat (Fix 6) -----
    // Per task 13a Fix 6: easiest source for the scheduler's start is the
    // first cycle the host's image stream is accepted (s_axis_tvalid &&
    // s_axis_tready). Latched so we don't re-pulse on every subsequent beat.
    reg sched_started_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) sched_started_r <= 1'b0;
        else if (s_axis_tvalid && s_axis_tready) sched_started_r <= 1'b1;
    end
