            if (sched_dispatch_idx != dispatch_idx_d) begin
                $display("[dbg-top] cycle=%0t dispatch_idx %0d -> %0d",
                         $time, dispatch_idx_d, sched_dispatch_idx);
            end
            // Print on each loader rising edge
            if (all_loaded & ~all_loaded_d) begin
                $display("[dbg-top] cycle=%0t all_loaded rose: now=%h prev=%h",
                         $time, all_loaded, all_loaded_d);
            end
            if (all_drain & ~all_drain_d) begin
                $display("[dbg-top] cycle=%0t all_drain rose: now=%h prev=%h",
                         $time, all_drain, all_drain_d);
            end
            if (engine_done && !engine_done_d) begin
                $display("[dbg-top] cycle=%0t engine_done RISE (dispatch %0d)",
                         $time, sched_dispatch_idx);
            end
            if (engine_start && !engine_start_d) begin
                $display("[dbg-top] cycle=%0t engine_start RISE (dispatch %0d)",
                         $time, sched_dispatch_idx);
            end
            if (sched_done && !sched_done_d) begin
                $display("[dbg-top] cycle=%0t sched_done RISE", $time);
            end
            if (node_conv_196_valid_out && !conv196_valid_d) begin
                // Only once
            end
        end
    end
    // ----- DEBUG: periodic counters for each chain module's valid_out -----
    // Prints every 5M cycles. Tells us if a stage is firing or stalled.
    integer cnt_conv196_v, cnt_relu_v, cnt_mp_v, cnt_conv198_v, cnt_conv200_v;
    integer cnt_conv202_v, cnt_conv204_v, cnt_add_v, cnt_relu3_v, cnt_relu22_v;
    integer cnt_conv206_v, cnt_conv208_v, cnt_conv210_v;
    integer cnt_relu12_v, cnt_relu15_v, cnt_relu18_v, cnt_relu21_v, cnt_conv244_v;
    integer cnt_r9o, cnt_r9_acc218, cnt_r9_acc224, cnt_c218i, cnt_c218o;
    integer cnt_c220i, cnt_c220o, cnt_r10o, cnt_r10_acc220;
    integer cnt_skidR31_cap, cnt_r31i, cnt_r31o, cnt_ldr5_cap;
    integer cnt_c282drain, cnt_c284in, cnt_c284out, cnt_ldr9cap;
    integer cnt_skidR40_deq, cnt_r40_cap;
    integer cnt_c288skip_in, cnt_add13_fire, cnt_add13_out;
    integer cnt_r42_cap, cnt_r42_bcast, cnt_add14skip_in;
    integer cnt_r42_produce;
    integer cnt_eng_busy, cnt_spat_run, cnt_stall;  // frame-partition profiler
    integer log_cycle;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt_conv196_v <= 0; cnt_relu_v <= 0; cnt_mp_v <= 0;
            cnt_conv198_v <= 0; cnt_conv200_v <= 0; cnt_conv202_v <= 0;
            cnt_conv204_v <= 0; cnt_add_v <= 0; cnt_relu3_v <= 0; cnt_relu22_v <= 0;
            cnt_conv206_v <= 0; cnt_conv208_v <= 0; cnt_conv210_v <= 0;
            cnt_relu12_v <= 0; cnt_relu15_v <= 0; cnt_relu18_v <= 0;
            cnt_relu21_v <= 0; cnt_conv244_v <= 0;
            cnt_r9o <= 0; cnt_r9_acc218 <= 0; cnt_r9_acc224 <= 0;
            cnt_c218i <= 0; cnt_c218o <= 0;
            cnt_c220i <= 0; cnt_c220o <= 0; cnt_r10o <= 0; cnt_r10_acc220 <= 0;
            cnt_skidR31_cap <= 0; cnt_r31i <= 0; cnt_r31o <= 0; cnt_ldr5_cap <= 0;
            cnt_c282drain <= 0; cnt_c284in <= 0; cnt_c284out <= 0; cnt_ldr9cap <= 0;
            cnt_skidR40_deq <= 0; cnt_r40_cap <= 0;
            cnt_c288skip_in <= 0; cnt_add13_fire <= 0; cnt_add13_out <= 0;
            cnt_r42_cap <= 0; cnt_r42_bcast <= 0; cnt_add14skip_in <= 0;
            cnt_r42_produce <= 0;
            cnt_eng_busy <= 0; cnt_spat_run <= 0; cnt_stall <= 0;
            log_cycle <= 0;
        end else begin
            // frame partition: engine-compute vs spatial-active vs stall(idle+frozen)
            if (engine_busy)               cnt_eng_busy <= cnt_eng_busy + 1;
            else if (sched_spatial_stall)  cnt_stall    <= cnt_stall + 1;
            else                           cnt_spat_run <= cnt_spat_run + 1;
            if (node_conv_264_valid_out & spatial_run & skid_node_relu_31_ready) cnt_skidR31_cap <= cnt_skidR31_cap + 1;
            if (skid_node_relu_31_valid & node_relu_31_ready_in)                cnt_r31i <= cnt_r31i + 1;
            if (node_relu_31_valid_out & node_relu_31_ready_out_combined & spatial_run) cnt_r31o <= cnt_r31o + 1;
            if (node_relu_31_valid_out & spatial_run & node_relu_31_ready_out_combined & ldr_node_conv_266_in_ready) cnt_ldr5_cap <= cnt_ldr5_cap + 1;
            // block-14 reduce path: conv_282(eng,d8) -> relu_40 -> conv_284(3x3) -> relu_41 -> ldr9 -> conv_286(eng,d9)
            if (node_conv_282_valid_out & spatial_run & skid_node_relu_40_ready)                                cnt_c282drain <= cnt_c282drain + 1;
            if (node_relu_40_valid_out & ldr_node_conv_284_in_ready & spatial_run)                                  cnt_c284in    <= cnt_c284in + 1;  // [K5] loader accept
            if (node_conv_284_valid_out & skid_node_relu_41_ready & spatial_run)                                cnt_c284out   <= cnt_c284out + 1;
            if (node_relu_41_valid_out & spatial_run & node_relu_41_ready_out_combined & ldr_node_conv_286_in_ready) cnt_ldr9cap <= cnt_ldr9cap + 1;
            // block-14 add_13 merge: conv_288->skip enqueue, add_13 fire (main+skip), add_13 out
            if (node_conv_288_valid_out & spatial_run & node_add_13_skip_in_ready)                              cnt_c288skip_in <= cnt_c288skip_in + 1;
            if (node_conv_286_valid_out & node_add_13_skip_valid & spatial_run & node_add_13_ready_in)          cnt_add13_fire  <= cnt_add13_fire + 1;
            if (node_add_13_valid_out & spatial_run & skid_node_relu_42_ready)                                  cnt_add13_out   <= cnt_add13_out + 1;
            // block-15 reduce: relu_42 input cap, broadcast out (= ldr10 cap = add_14 skip cap), add_14 skip enqueue
            if (skid_node_relu_42_valid & node_relu_42_ready_in)                                                cnt_r42_cap     <= cnt_r42_cap + 1;
            if (node_relu_42_valid_out & node_relu_42_ready_out_combined)                         cnt_r42_bcast   <= cnt_r42_bcast + 1;
            // relu_42 INTERNAL output-beat productions (transition emits beat0 + each sending advance)
            if ( (!u_node_relu_42.sending & skid_node_relu_42_valid & node_relu_42_ready_in & (u_node_relu_42.in_beat_count == 7'd63))
                 | (u_node_relu_42.sending & node_relu_42_ready_out_combined) )                                 cnt_r42_produce <= cnt_r42_produce + 1;
            if (node_relu_42_valid_out & node_relu_42_ready_out_combined & node_add_14_skip_in_ready) cnt_add14skip_in <= cnt_add14skip_in + 1;
            // skid_relu_40 dequeue (gated by spatial_run) vs relu_40 input capture (NOT gated)
            if (skid_node_relu_40_valid & node_relu_40_ready_in & spatial_run) cnt_skidR40_deq <= cnt_skidR40_deq + 1;
            if (skid_node_relu_40_valid & node_relu_40_ready_in)               cnt_r40_cap     <= cnt_r40_cap + 1;
            if (node_conv_196_valid_out)   cnt_conv196_v <= cnt_conv196_v + 1;
            if (node_relu_valid_out)       cnt_relu_v    <= cnt_relu_v    + 1;
            if (node_max_pool2d_valid_out) cnt_mp_v      <= cnt_mp_v      + 1;
            if (node_conv_198_valid_out)   cnt_conv198_v <= cnt_conv198_v + 1;
            if (node_conv_200_valid_out)   cnt_conv200_v <= cnt_conv200_v + 1;
            if (node_conv_202_valid_out)   cnt_conv202_v <= cnt_conv202_v + 1;
            if (node_conv_204_valid_out)   cnt_conv204_v <= cnt_conv204_v + 1;
            if (node_add_valid_out)        cnt_add_v     <= cnt_add_v     + 1;
            if (node_relu_3_valid_out)     cnt_relu3_v   <= cnt_relu3_v   + 1;
            if (node_relu_22_valid_out)    cnt_relu22_v  <= cnt_relu22_v  + 1;
            if (node_conv_206_valid_out)   cnt_conv206_v <= cnt_conv206_v + 1;
            if (node_conv_208_valid_out)   cnt_conv208_v <= cnt_conv208_v + 1;
            if (node_conv_210_valid_out)   cnt_conv210_v <= cnt_conv210_v + 1;
            if (node_relu_12_valid_out)    cnt_relu12_v  <= cnt_relu12_v  + 1;
            if (node_relu_15_valid_out)    cnt_relu15_v  <= cnt_relu15_v  + 1;
            if (node_relu_18_valid_out)    cnt_relu18_v  <= cnt_relu18_v  + 1;
            if (node_relu_21_valid_out)    cnt_relu21_v  <= cnt_relu21_v  + 1;
            if (node_conv_244_valid_out)   cnt_conv244_v <= cnt_conv244_v + 1;
            // OPTION A: count handshake fires (valid_out held high during stalls).
            if (node_relu_9_valid_out & relu_9_dual_ready)                      cnt_r9o       <= cnt_r9o       + 1;
            if (node_relu_9_valid_out & spatial_run & relu_9_dual_ready)        cnt_r9_acc218 <= cnt_r9_acc218 + 1;
            if (node_relu_9_valid_out & spatial_run & relu_9_dual_ready)        cnt_r9_acc224 <= cnt_r9_acc224 + 1;
            if (skid_node_conv_218_valid & node_conv_218_ready_in)              cnt_c218i     <= cnt_c218i     + 1;
            if (node_conv_218_valid_out)                                        cnt_c218o     <= cnt_c218o     + 1;
            if (node_relu_10_valid_out)                                         cnt_r10o      <= cnt_r10o      + 1;
            if (node_relu_10_valid_out & spatial_run & skid_node_conv_220_ready) cnt_r10_acc220 <= cnt_r10_acc220 + 1;
            if (skid_node_conv_220_valid & node_conv_220_ready_in)              cnt_c220i     <= cnt_c220i     + 1;
            if (node_conv_220_valid_out)                                        cnt_c220o     <= cnt_c220o     + 1;
            log_cycle <= log_cycle + 1;
            if (log_cycle > 0 && log_cycle % 1000000 == 0) begin
                $display("[dbg-cnt @cyc=%0d] c196=%0d relu=%0d mp=%0d c198=%0d c200=%0d c202=%0d c204=%0d add=%0d relu3=%0d c206=%0d c208=%0d c210=%0d r12=%0d r15=%0d r18=%0d r21=%0d c244=%0d relu22=%0d  loaded=%h drain=%h disp_idx=%0d engine_busy=%b",
                         log_cycle, cnt_conv196_v, cnt_relu_v, cnt_mp_v,
                         cnt_conv198_v, cnt_conv200_v, cnt_conv202_v, cnt_conv204_v,
                         cnt_add_v, cnt_relu3_v, cnt_conv206_v, cnt_conv208_v, cnt_conv210_v,
                         cnt_relu12_v, cnt_relu15_v, cnt_relu18_v, cnt_relu21_v, cnt_conv244_v,
                         cnt_relu22_v, all_loaded, all_drain, sched_dispatch_idx, engine_busy);
                $display("[dbg-partition @cyc=%0d] eng_busy=%0d spat_run=%0d stall=%0d (sum=%0d)",
                         log_cycle, cnt_eng_busy, cnt_spat_run, cnt_stall,
                         cnt_eng_busy + cnt_spat_run + cnt_stall);
                $display("[dbg-boundary @cyc=%0d] r9_emit=%0d r9_to_skid218=%0d r9_to_skid224=%0d c218_in=%0d c218_out=%0d r10_emit=%0d r10_to_skid220=%0d c220_in=%0d c220_out=%0d",
                         log_cycle, cnt_r9o, cnt_r9_acc218, cnt_r9_acc224, cnt_c218i, cnt_c218o,
                         cnt_r10o, cnt_r10_acc220, cnt_c220i, cnt_c220o);
                $display("[dbg-eng @cyc=%0d] ldr0_req=%b ldr0_grant=%b ldr0_bridge_inready=%b ldr0_loaded=%b eng_actwr=%b current_loaded=%b sched_stall=%b disp_idx=%0d eng_busy=%b eng_start=%b r22_vo=%b r22_rdyout=%b",
                         log_cycle, ldr0_wr_req, ldr0_wr_grant, ldr_node_conv_246_in_ready, ldr0_loaded,
                         engine_act_out_wr_en, current_loaded, sched_spatial_stall, sched_dispatch_idx,
                         engine_busy, engine_start, node_relu_22_valid_out, node_relu_22_ready_out_combined);
                $display("[dbg-blk8 @cyc=%0d] r21_vo=%b r21_rdyout=%b skid244_rdy=%b add7skip_rdy=%b c244_vo=%b c246_vo=%b r23_vo=%b c248_vo=%b ldr1_loaded=%b c250_vo=%b add7_rdyin=%b add7_skipvalid=%b",
                         log_cycle, node_relu_21_valid_out, node_relu_21_ready_out_combined,
                         skid_node_conv_244_ready, node_add_7_skip_in_ready, node_conv_244_valid_out,
                         node_conv_246_valid_out, node_relu_23_valid_out, node_conv_248_valid_out,
                         ldr1_loaded, node_conv_250_valid_out, node_add_7_ready_in, node_add_7_skip_valid);
                $display("[dbg-reentry @cyc=%0d] drain246=%b skidR23_v=%b skidR23_rdy=%b r23_rdyin=%b skidC248_v=%b skidC248_rdy=%b c248_busy=%b c248_mac=%b c248_fst=%0d c248_schrdy=%b ldr1_inrdy=%b ldr1_req=%b ldr1_grant=%b",
                         log_cycle, u_engine_out_node_conv_246_drain_complete,
                         skid_node_relu_23_valid, skid_node_relu_23_ready, node_relu_23_ready_in,
                         skid_node_conv_248_valid, skid_node_conv_248_ready,
                         u_node_conv_248.out_busy, u_node_conv_248.mac_busy, u_node_conv_248.frame_state,
                         u_node_conv_248.sched_ready_in, ldr_node_conv_250_in_ready, ldr1_wr_req, ldr1_wr_grant);
                $display("[dbg-blk11 @cyc=%0d] drain264=%b skidR31_v=%b skidR31_rdy=%b r31_vo=%b r31_rdyin=%b ldr266_inrdy=%b ldr5_loaded=%b ldr5_req=%b ldr5_grant=%b reqs01234=%b%b%b%b%b",
                         log_cycle, u_engine_out_node_conv_264_drain_complete,
                         skid_node_relu_31_valid, skid_node_relu_31_ready, node_relu_31_valid_out, node_relu_31_ready_in,
                         ldr_node_conv_266_in_ready, ldr5_loaded, ldr5_wr_req, ldr5_wr_grant,
                         ldr0_wr_req, ldr1_wr_req, ldr2_wr_req, ldr3_wr_req, ldr4_wr_req);
                $display("[dbg-blk11cnt @cyc=%0d] skidR31_cap=%0d r31_in=%0d r31_out=%0d ldr5_cap=%0d",
                         log_cycle, cnt_skidR31_cap, cnt_r31i, cnt_r31o, cnt_ldr5_cap);
                // [dbg-w288 removed: conv_288 is now on-chip split-arch, no AXI weight ports]
                $display("[dbg-blk7 @cyc=%0d] r18_vo=%b r18_rdyout=%b skid238_rdy=%b c238_vo=%b c240_vo=%b c242_vo=%b add6_skipvalid=%b add6_rdyin=%b add6_vo=%b skidR21_rdy=%b r21_vo=%b",
                         log_cycle, node_relu_18_valid_out, node_relu_18_ready_out_combined,
                         skid_node_conv_238_ready, node_conv_238_valid_out, node_conv_240_valid_out,
                         node_conv_242_valid_out, node_add_6_skip_valid, node_add_6_ready_in,
                         node_add_6_valid_out, skid_node_relu_21_ready, node_relu_21_valid_out);
                $display("[dbg-blk14 @cyc=%0d] r39_vo=%b r39_rdyout=%b ldr8_inrdy=%b ldr8_loaded=%b | skidC288_v=%b skidC288_inrdy=%b c288_rdyin=%b c288_vo=%b add13skip_inrdy=%b add13skip_v=%b c284_vo=%b c286_vo=%b | c288[outbusy=%b mac=%b fst=%0d ibeat=%0d irow=%0d icol=%0d] disp=%0d",
                         log_cycle, node_relu_39_valid_out, node_relu_39_ready_out_combined,
                         ldr_node_conv_282_in_ready, ldr8_loaded,
                         skid_node_conv_288_valid, skid_node_conv_288_in_ready,
                         node_conv_288_ready_in, node_conv_288_valid_out,
                         node_add_13_skip_in_ready, node_add_13_skip_valid,
                         node_conv_284_valid_out, node_conv_286_valid_out,
                         u_node_conv_288.out_busy, u_node_conv_288.mac_busy, u_node_conv_288.frame_state,
                         u_node_conv_288.in_beat_idx, u_node_conv_288.irow, u_node_conv_288.icol,
                         sched_dispatch_idx);
                // [K5] dbg-blk14cnt display removed (referenced deleted spatial u_node_conv_284)
                $display("[dbg-add13 @cyc=%0d] c288skip_in=%0d(of3136) add13_fire=%0d(of3136) add13_out=%0d skip_v=%b skip_inrdy=%b c286_vo=%b add13_rdyin=%b",
                         log_cycle, cnt_c288skip_in, cnt_add13_fire, cnt_add13_out,
                         node_add_13_skip_valid, node_add_13_skip_in_ready, node_conv_286_valid_out, node_add_13_ready_in);
                $display("[dbg-blk15 @cyc=%0d] r42_cap=%0d r42_produce=%0d r42_bcast=%0d add14skip_in=%0d | ldr10_loaded=%b ldr10_inrdy=%b add14skip_inrdy=%b | r42[sending=%b in_cnt=%0d out_cnt=%0d] r42_vo=%b skidR42_v=%b disp=%0d",
                         log_cycle, cnt_r42_cap, cnt_r42_produce, cnt_r42_bcast, cnt_add14skip_in,
                         ldr10_loaded, ldr_node_conv_290_in_ready, node_add_14_skip_in_ready,
                         u_node_relu_42.sending, u_node_relu_42.in_beat_count, u_node_relu_42.out_beat_count,
                         node_relu_42_valid_out, skid_node_relu_42_valid, sched_dispatch_idx);
                $display("[dbg-r40 @cyc=%0d] skidR40_deq=%0d r40_cap=%0d (c282drain=%0d c284in=%0d) | r40[sending=%b in_cnt=%0d out_cnt=%0d ready_in=%b] r40_rdyout(c284rdy&sr)=%b",
                         log_cycle, cnt_skidR40_deq, cnt_r40_cap, cnt_c282drain, cnt_c284in,
                         u_node_relu_40.sending, u_node_relu_40.in_beat_count, u_node_relu_40.out_beat_count,
                         u_node_relu_40.ready_in, (ldr_node_conv_284_in_ready & spatial_run));  // [K5]
            end
            // [DBG-BLK1-CYCLE] per-cycle block-1 add handshake at the freeze window.
            if (log_cycle >= 27000000 && log_cycle < 27000050) begin
                $display("[dbg-blk1 cyc=%0d] sp_run=%b c202_vo=%b add_skipv=%b add_rdyin=%b add_vo=%b skidR3_rdy=%b c204_vo=%b",
                         log_cycle, spatial_run, node_conv_202_valid_out, node_add_skip_valid,
                         node_add_ready_in, node_add_valid_out, skid_node_relu_3_ready, node_conv_204_valid_out);
                $display("[dbg-c202 cyc=%0d] mac_busy=%b out_busy=%b out_idx=%0d lib_vin=%b sched_rdyin=%b sched_ofires=%b frame_st=%0d in_beat=%0d lib_vout=%b skid202in_rdy=%b skid202out_v=%b",
                         log_cycle, u_node_conv_202.mac_busy, u_node_conv_202.out_busy, u_node_conv_202.out_idx,
                         u_node_conv_202.lib_valid_in_w, u_node_conv_202.sched_ready_in, u_node_conv_202.sched_output_fires,
                         u_node_conv_202.frame_state, u_node_conv_202.in_beat_idx, u_node_conv_202.lib_valid_out_w,
                         skid_node_conv_202_ready, skid_node_conv_202_valid);
            end
        end
    end

    // ----- Below: keep the per-stage FIRST events for chronological ordering -----
    reg [7:0] rst_settled_cnt;
    wire rst_settled = (rst_settled_cnt == 8'hff);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) rst_settled_cnt <= 8'd0;
        else if (rst_settled_cnt != 8'hff) rst_settled_cnt <= rst_settled_cnt + 8'd1;
    end
    reg seen_conv196_o, seen_relu_o, seen_mp_o, seen_conv198_o, seen_conv200_o;
    reg seen_conv202_o, seen_conv204_o, seen_add_o, seen_relu3_o, seen_relu22_o;
    reg seen_conv206_o, seen_conv208_o, seen_conv210_o, seen_relu6_o, seen_relu9_o;
    integer add_fire_count;
    integer conv204_fire_count;
    integer skip_fifo_fire_count;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            seen_conv196_o <= 0; seen_relu_o <= 0; seen_mp_o <= 0;
            seen_conv198_o <= 0; seen_conv200_o <= 0; seen_conv202_o <= 0;
            seen_conv204_o <= 0; seen_add_o <= 0; seen_relu3_o <= 0; seen_relu22_o <= 0;
            seen_conv206_o <= 0; seen_conv208_o <= 0; seen_conv210_o <= 0;
            seen_relu6_o <= 0; seen_relu9_o <= 0;
            add_fire_count <= 0;
            conv204_fire_count <= 0;
            skip_fifo_fire_count <= 0;
        end else if (rst_settled) begin
            if (node_conv_196_valid_out  && !seen_conv196_o)  begin seen_conv196_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_196 valid_out",  $time); end
            if (node_relu_valid_out      && !seen_relu_o)     begin seen_relu_o    <= 1;  $display("[dbg-chain] @%0t FIRST relu valid_out",      $time); end
            if (node_max_pool2d_valid_out&& !seen_mp_o)       begin seen_mp_o      <= 1;  $display("[dbg-chain] @%0t FIRST maxpool valid_out",   $time); end
            if (node_conv_198_valid_out  && !seen_conv198_o)  begin seen_conv198_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_198 valid_out",  $time); end
            if (node_conv_200_valid_out  && !seen_conv200_o)  begin seen_conv200_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_200 valid_out",  $time); end
            if (node_conv_202_valid_out  && !seen_conv202_o)  begin seen_conv202_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_202 valid_out",  $time); end
            if (node_conv_204_valid_out  && !seen_conv204_o)  begin seen_conv204_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_204 valid_out",  $time); end
            if (node_add_valid_out       && !seen_add_o)      begin seen_add_o     <= 1;  $display("[dbg-chain] @%0t FIRST add valid_out",       $time); end
            if (node_relu_3_valid_out    && !seen_relu3_o)    begin seen_relu3_o   <= 1;  $display("[dbg-chain] @%0t FIRST relu_3 valid_out",    $time); end
            if (node_conv_206_valid_out  && !seen_conv206_o)  begin seen_conv206_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_206 valid_out",  $time); end
            if (node_conv_208_valid_out  && !seen_conv208_o)  begin seen_conv208_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_208 valid_out",  $time); end
            if (node_conv_210_valid_out  && !seen_conv210_o)  begin seen_conv210_o <= 1;  $display("[dbg-chain] @%0t FIRST conv_210 valid_out",  $time); end
            if (node_relu_6_valid_out    && !seen_relu6_o)    begin seen_relu6_o   <= 1;  $display("[dbg-chain] @%0t FIRST relu_6 valid_out",    $time); end
            if (node_relu_9_valid_out    && !seen_relu9_o)    begin seen_relu9_o   <= 1;  $display("[dbg-chain] @%0t FIRST relu_9 valid_out",    $time); end
            if (node_relu_22_valid_out   && !seen_relu22_o)   begin seen_relu22_o  <= 1;  $display("[dbg-chain] @%0t FIRST relu_22 valid_out",   $time); end
            // Running counters for add chain to see steady-state rate
            if (node_conv_204_valid_out) conv204_fire_count <= conv204_fire_count + 1;
            if (node_add_valid_out) add_fire_count <= add_fire_count + 1;
            if (node_add_skip_valid)     skip_fifo_fire_count <= skip_fifo_fire_count + 1;
            // Periodically print add chain rate
            if ((rst_settled_cnt == 8'hff) && ((rst_settled_cnt) == 8'hff) && ($time % 10000000 == 0) && ($time > 0)) begin
                $display("[dbg-rate] @%0t conv_204_total=%0d add_total=%0d skip_valid_total=%0d",
                         $time, conv204_fire_count, add_fire_count, skip_fifo_fire_count);
            end
        end
    end

    // ----- network output (Fix #4: tlast on final output beat) -----
    assign m_axis_tvalid = node_relu_48_valid_out;
    assign m_axis_tdata  = node_relu_48_data_out;
    // Output frame size: C=2048 H=7 W=7, busOut=256b -> 3136 beats
    reg [11:0] m_axis_beat_count;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            m_axis_beat_count <= 12'd0;
        end else if (m_axis_tvalid & m_axis_tready) begin
            if (m_axis_beat_count == 12'd3135)
                m_axis_beat_count <= 12'd0;
            else
                m_axis_beat_count <= m_axis_beat_count + 12'd1;
        end
    end
    assign m_axis_tlast = (m_axis_beat_count == 12'd3135);

endmodule

`ifndef NN2RTL_TOP_NO_STUBS
// ===== Wrapper-local module bodies (suppress with `define NN2RTL_TOP_NO_STUBS) =====

module skip_fifo #(
    parameter integer WIDTH = 8,
    parameter integer DEPTH = 16
) (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              in_valid,
    input  wire [WIDTH-1:0]  in_data,
    output wire              in_ready,
    output wire              out_valid,
    output wire [WIDTH-1:0]  out_data,
    input  wire              out_ready
);
    // DEPTH must be a power of 2; ADDR_W = log2(DEPTH).
    function integer clog2;
        input integer value;
        integer v;
        begin
            v = value - 1;
            for (clog2 = 0; v > 0; clog2 = clog2 + 1) v = v >> 1;
        end
    endfunction
    localparam integer ADDR_W = clog2(DEPTH);

    reg [ADDR_W:0]  wr_ptr;
    reg [ADDR_W:0]  rd_ptr;
    // [fifo-peak audit] high-water occupancy, printed per-instance at sim end.
    reg  [ADDR_W:0] peak_occ;
    wire [ADDR_W:0] occ_now = wr_ptr - rd_ptr;

    wire [ADDR_W-1:0] wr_idx = wr_ptr[ADDR_W-1:0];
    wire [ADDR_W-1:0] rd_idx = rd_ptr[ADDR_W-1:0];
    wire mem_empty = (wr_ptr == rd_ptr);
    // full when low bits match but top bit differs (one-extra-bit pointer trick).
    wire full  = (wr_ptr[ADDR_W] != rd_ptr[ADDR_W]) &&
                 (wr_ptr[ADDR_W-1:0] == rd_ptr[ADDR_W-1:0]);

    assign in_ready  = ~full;

    // [FIT-FIX 2026-05-30] DEPTH-conditional implementation.
    //   DEPTH >= 512 (the 36 deep residual/skip FIFOs): REGISTERED-read FWFT FIFO
    //     mapped to URAM (ram_style="ultra"). URAM has NO combinational read, so the
    //     output is a 1-deep prefetch register fed by mem[rd_idx]. This frees ~424K
    //     LUT-as-distributed-RAM (Vivado REJECTS ram_style on the old combinational
    //     read as "Infeasible"). Capacity = DEPTH+1 (>= old DEPTH) -> still lossless.
    //     +1 read latency; valid/ready handshake absorbs it (data values + order
    //     unchanged -> byte-exact). Runtime data, no init -> URAM-safe.
    //   DEPTH < 512 (the tiny skids): original combinational-read LUTRAM (unchanged).
    generate
    if (DEPTH >= 512) begin : g_uram_fifo
        (* ram_style = "ultra" *) reg [WIDTH-1:0] mem [0:DEPTH-1];
        reg [WIDTH-1:0] out_data_r;
        reg             out_valid_r;
        // prefetch the output register whenever storage has data and the reg is
        // free (empty, or being consumed this cycle).
        wire do_rd = ~mem_empty && (~out_valid_r || out_ready);
        assign out_valid = out_valid_r;
        assign out_data  = out_data_r;
        // [K1-FDCE] out_data_r is FIFO DATA: sampled downstream only under
        // out_valid_r (kept async-reset); written only under do_rd (gated by
        // reset-held pointers). Sync-only write, reset dropped -> FDRE.
        always @(posedge clk) begin
            if (do_rd) out_data_r <= mem[rd_idx];
        end
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_ptr <= {(ADDR_W+1){1'b0}};
                rd_ptr <= {(ADDR_W+1){1'b0}};
                peak_occ <= {(ADDR_W+1){1'b0}};
                out_valid_r <= 1'b0;
            end else begin
                if (in_valid && ~full) wr_ptr <= wr_ptr + 1'b1;
                if (do_rd) begin
                    out_valid_r <= 1'b1;
                    rd_ptr      <= rd_ptr + 1'b1;
                end else if (out_valid_r && out_ready) begin
                    out_valid_r <= 1'b0;
                end
                if (occ_now > peak_occ) peak_occ <= occ_now;
            end
        end
        always @(posedge clk) begin
            if (in_valid && ~full) mem[wr_idx] <= in_data;
        end
    end else begin : g_lut_fifo
        reg [WIDTH-1:0] mem [0:DEPTH-1];
        assign out_valid = ~mem_empty;
        assign out_data  = mem[rd_idx];
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_ptr <= {(ADDR_W+1){1'b0}};
                rd_ptr <= {(ADDR_W+1){1'b0}};
                peak_occ <= {(ADDR_W+1){1'b0}};
            end else begin
                if (in_valid && ~full)   wr_ptr <= wr_ptr + 1'b1;
                if (out_ready && ~mem_empty) rd_ptr <= rd_ptr + 1'b1;
                if (occ_now > peak_occ)  peak_occ <= peak_occ + (occ_now - peak_occ);
            end
        end
        always @(posedge clk) begin
            if (in_valid && ~full) mem[wr_idx] <= in_data;
        end
    end
    endgenerate

    // [fifo-peak audit] print each instance's high-water occupancy at sim end.
    final $display("[fifo-peak] %m DEPTH=%0d peak=%0d", DEPTH, peak_occ);
endmodule

module uram_weight_bank #(
    parameter integer DEPTH         = 1024,
    parameter integer ADDR_W        = 17,
    // [INT3-MIXED] bank word width: 144 = INT4 (32 nibbles + 16 dead, low 128
    // used); 96 = INT3 (32x3, no dead). Driven by ENGINE_BANK_W at the top.
    parameter integer WORD_W        = 144,
    parameter         MEM_INIT_FILE = ""
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    output wire [WORD_W-1:0]        rd_data,   // WGT-packed weight word
    input  wire                    rd_en
);
    // [ENGINE BRAM 2026-05-30] Inferred block-RAM ROM with $readmemh init — ONE path
    // for sim (Verilator/iverilog) AND Vivado synth. Replaces the old XPM-URAM (ultra)
    // branch: URAM CANNOT be bitstream-initialized on this device (proven), and the
    // XPM-URAM + $readmemh fallback blew up BRAM/LUTs. ram_style="block" + $readmemh is
    // bitstream-initializable (Vivado packs the init into the BRAM INIT_xx strings, same
    // mechanism as bias_mem/scale_mem). The TWO output register stages (rd_data_r1 ->
    // rd_data_r2) preserve the READ_LATENCY=2 contract (the hard-won 8677bc0 weight-read-
    // latency alignment) — do NOT collapse to one stage. INT4 nibble-packed: 144-bit lines.
    // [FIT-FIX 2026-05-30] cascade_height=8 stops Vivado rounding the 39424-deep
    // ROM up to 65536 (a 40% depth waste): 256->160 RAMB36/bank (x8 banks = -768
    // BRAM total), MEASURED via OOC synth. Byte-exact: synth-only attribute, no
    // .mem/address/value change; Verilator/iverilog ignore it.
    // [FIT 2026-05-31] reg width = WORD_W (was hardcoded 143:0). For INT3 (ENGINE_WGT_W=3)
    // WORD_W=ENGINE_BANK_W=96 -> the ROM synthesizes 96-bit not 144-bit => ~1/3 fewer RAMB36
    // tiles/bank. BYTE-EXACT: .mem lines are 24 hex chars (96b), right-justified by $readmemh
    // (the upper 48b of the old 144b reg were always 0) and rd_data is [WORD_W-1:0] (only the
    // low 96b were ever read). INT4 keeps WORD_W=144 (unchanged). Verilator/iverilog identical.
    (* ram_style = "block", cascade_height = 8 *) reg [WORD_W-1:0] mem [0:DEPTH-1];
    initial begin
        if (MEM_INIT_FILE != "") $readmemh(MEM_INIT_FILE, mem);
    end
    reg [WORD_W-1:0] rd_data_r1, rd_data_r2;
    always @(posedge clk) begin
        if (rd_en) rd_data_r1 <= mem[rd_addr];
        rd_data_r2 <= rd_data_r1;
    end
    assign rd_data = rd_data_r2;
endmodule

module stream_to_act_bram_bridge #(
    parameter integer BUS_W            = 2048,
    parameter integer BRAM_BASE_ADDR   = 0,
    parameter integer TOTAL_BRAM_WORDS = 1
) (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             in_valid,
    input  wire [BUS_W-1:0] in_data,
    output wire             in_ready,   // OPTION A: backpressure to producer
    output reg              wr_req,
    input  wire             wr_grant,
    output reg  [14:0]      wr_addr,
    output reg  [2047:0]    wr_data,
    output reg              loaded
);
    // Word counter (BRAM words written so far).
    reg [15:0] word_count;
    wire [15:0] next_word_count = word_count + 16'd1;
    // bridge_free pulses when wr_req is empty OR being granted this cycle.
    wire bridge_free = !wr_req || (wr_req && wr_grant);
    // wr_addr to use when bridge_free fires this cycle (use next_word_count
    // if a grant just retired the previous wr_req).
    wire [14:0] next_wr_addr = BRAM_BASE_ADDR[14:0]
                             + ((wr_req && wr_grant) ? next_word_count[14:0]
                                                     : word_count[14:0]);

    generate
    if (BUS_W == 2048) begin : g_w_eq
        // OPTION A: ready_in = condition under which next in_valid would be captured.
        // Mirrors line "if (in_valid && !loaded && (!skid_valid || drain_skid))" below.
        // (1) skid_valid/drain_skid are declared in this branch's scope below.
        // 13a audit fix (Fix 12): 1-deep producer-side skid buffer.
        // Previously the old "else if (in_valid && !wr_req)" guard dropped
        // every beat that arrived while wr_req was pending — including the
        // every-other-cycle case where grant+beat coincide. The skid lets
        // us accept a beat in cycle N while wr_data from cycle N-1 is
        // still on the bus, then submit it cycle N+1. Steady-state grant
        // yields one BRAM write per beat, lossless.
        //
        // Known limitation: multi-cycle grant denial (when several bridges
        // and the engine all contend) still drops beats after the skid
        // fills. For the ResNet-50 schedule's mild contention pattern this
        // is rare; a deeper FIFO can be added later if it becomes a hot
        // path in Verilator simulation.
        reg [2047:0] skid_data;
        reg          skid_valid;
        wire         drain_skid = skid_valid && bridge_free;
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        // [K1-FDCE] Block A: stream DATA regs (sync-only, no reset). wr_data is
        // consumed only while wr_req is pending; skid_data only while
        // skid_valid -- both controls stay async-reset below. Reset values dead.
        always @(posedge clk) begin
            if (drain_skid) wr_data <= skid_data;
            if (in_valid && !loaded && (!skid_valid || drain_skid))
                skid_data <= in_data;
        end
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req     <= 1'b0;
                wr_addr    <= 15'd0;
                word_count <= 16'd0;
                loaded     <= 1'b0;
                skid_valid <= 1'b0;
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                end
                // (2) Drain skid into wr_req when bridge is free.
                if (drain_skid) begin
                    wr_req  <= 1'b1;
                    wr_addr <= next_wr_addr;
                end
                // (3) Capture new beat into skid; clear skid if drained and no new.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end else if (BUS_W < 2048) begin : g_w_lt
        // Accumulate BEATS_PER_WORD beats into one BRAM word, with a
        // 1-deep producer-side skid so beats are not lost when the
        // BRAM write port is denied for a cycle.
        localparam integer BEATS_PER_WORD = 2048 / BUS_W;
        localparam integer BEAT_W = $clog2(BEATS_PER_WORD);
        reg [2047:0] accumulator;
        reg [BEAT_W:0] beat_idx;
        reg [BUS_W-1:0] skid_data;
        reg             skid_valid;
        // The accumulator absorbs a skid beat each cycle UNLESS the
        // beat would complete a new word AND wr_req is still pending
        // (then we have to hold the new word — currently we just stall
        // the accumulator until wr_req retires).
        wire would_complete = (beat_idx == BEATS_PER_WORD - 1);
        wire drain_skid = skid_valid && (!would_complete || bridge_free);
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        // [K1-FDCE] Block A: stream DATA regs (sync-only, no reset). The
        // accumulator's consumed slices are all (re)written each word before
        // wr_data is formed; wr_data/skid_data are consumed only under
        // wr_req/skid_valid (async-reset control below). Reset values dead.
        always @(posedge clk) begin
            if (drain_skid) begin
                accumulator[beat_idx*BUS_W +: BUS_W] <= skid_data;
                if (would_complete)
                    wr_data <= { skid_data,
                                 accumulator[2048-BUS_W-1:0] };
            end
            if (in_valid && !loaded && (!skid_valid || drain_skid))
                skid_data <= in_data;
        end
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req      <= 1'b0;
                wr_addr     <= 15'd0;
                word_count  <= 16'd0;
                beat_idx    <= {(BEAT_W+1){1'b0}};
                loaded      <= 1'b0;
                skid_valid  <= 1'b0;
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                end
                // (2) Drain skid (data writes moved to Block A above).
                if (drain_skid) begin
                    if (would_complete) begin
                        beat_idx <= {(BEAT_W+1){1'b0}};
                        wr_req   <= 1'b1;
                        wr_addr  <= next_wr_addr;
                    end else begin
                        beat_idx <= beat_idx + 1'b1;
                    end
                end
                // (3) Capture new beat into skid.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end else begin : g_w_gt
        // BUS_W > 2048: each beat carries WORDS_PER_BEAT BRAM words.
        // 1-deep skid lets a new beat be queued while the current
        // is still being sliced.
        localparam integer WORDS_PER_BEAT = BUS_W / 2048;
        localparam integer SLICE_W = $clog2(WORDS_PER_BEAT);
        reg [BUS_W-1:0] beat_buf;
        reg [SLICE_W:0] slice_idx;
        reg             buf_active;
        reg [BUS_W-1:0] skid_data;
        reg             skid_valid;
        wire beat_complete = buf_active && wr_req && wr_grant
                           && (slice_idx == WORDS_PER_BEAT - 1);
        wire can_load_new  = !buf_active || beat_complete;
        wire drain_skid    = skid_valid && can_load_new;
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        // [K1-FDCE] Block A: stream DATA regs (sync-only, no reset), consumed
        // only under wr_req/buf_active/skid_valid (async-reset control below).
        // Textual order preserved: a drain_skid wr_data write overrides the
        // continue-slice write, exactly as in the original single block.
        always @(posedge clk) begin
            if (wr_req && wr_grant && (slice_idx != WORDS_PER_BEAT - 1)
                && (next_word_count != TOTAL_BRAM_WORDS))
                wr_data <= beat_buf[(slice_idx+1)*2048 +: 2048];
            if (drain_skid) begin
                beat_buf <= skid_data;
                wr_data  <= skid_data[2047:0];
            end
            if (in_valid && !loaded && (!skid_valid || drain_skid))
                skid_data <= in_data;
        end
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req     <= 1'b0;
                wr_addr    <= 15'd0;
                word_count <= 16'd0;
                slice_idx  <= {(SLICE_W+1){1'b0}};
                buf_active <= 1'b0;
                loaded     <= 1'b0;
                skid_valid <= 1'b0;
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                    if (slice_idx == WORDS_PER_BEAT - 1) begin
                        slice_idx  <= {(SLICE_W+1){1'b0}};
                        buf_active <= 1'b0;
                    end else if (next_word_count != TOTAL_BRAM_WORDS) begin
                        // Continue slicing the current beat (defensive guard
                        // on next_word_count so we don't overrun TOTAL_BRAM_WORDS
                        // when a frame ends mid-beat with a non-divisible total).
                        slice_idx <= slice_idx + 1'b1;
                        wr_req    <= 1'b1;
                        wr_addr   <= BRAM_BASE_ADDR[14:0] + next_word_count[14:0];
                    end
                end
                // (2) Load new beat from skid when buf is free.
                if (drain_skid) begin
                    buf_active <= 1'b1;
                    slice_idx  <= {(SLICE_W+1){1'b0}};
                    wr_req     <= 1'b1;
                    wr_addr    <= next_wr_addr;
                end
                // (3) Capture new beat into skid.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end
    endgenerate
endmodule

module act_unified_mem #(
    parameter integer DEPTH  = 24576,
    parameter integer ADDR_W = 15
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    input  wire                    rd_en,
    output reg  [2047:0]           rd_data,
    input  wire [ADDR_W-1:0]       wr_addr,
    input  wire                    wr_en,
    input  wire [2047:0]           wr_data
);
    (* ram_style = "ultra" *) reg [2047:0] mem [0:DEPTH-1];
    always @(posedge clk) begin
        if (rd_en) rd_data <= mem[rd_addr];
    end
    // Array-memory write split into its own always block per
    // knowledge/patterns/protected/08_common_bugs.md §"Array memory
    // write in async-reset block" — no reset clause here.
    always @(posedge clk) begin
        if (wr_en) mem[wr_addr] <= wr_data;
    end
endmodule

module engine_output_fifo #(
    parameter integer DEPTH  = 4096,
    parameter integer ADDR_W = 12,             // log2(DEPTH)
    parameter integer DATA_W = 2048
) (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             in_valid,
    input  wire [DATA_W-1:0] in_data,
    output wire             in_ready,
    output reg              out_valid,
    output reg  [DATA_W-1:0] out_data,
    input  wire             out_ready
);
    (* ram_style = "ultra" *) reg [DATA_W-1:0] mem [0:DEPTH-1];
    reg [ADDR_W:0] wr_ptr;
    reg [ADDR_W:0] rd_ptr;

    wire fifo_empty = (wr_ptr == rd_ptr);
    wire fifo_full  = (wr_ptr[ADDR_W-1:0] == rd_ptr[ADDR_W-1:0])
                    && (wr_ptr[ADDR_W] != rd_ptr[ADDR_W]);
    wire wr_fire = in_valid && !fifo_full;
    wire load_skid = !fifo_empty && (!out_valid || (out_valid && out_ready));
    assign in_ready = !fifo_full;

    // [K1-FDCE] out_data is FIFO DATA: sampled only under out_valid (kept
    // async-reset); written only under load_skid. Sync-only write -> FDRE.
    always @(posedge clk) begin
        if (load_skid) out_data <= mem[rd_ptr[ADDR_W-1:0]];
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr    <= {(ADDR_W+1){1'b0}};
            rd_ptr    <= {(ADDR_W+1){1'b0}};
            out_valid <= 1'b0;
        end else begin
            if (wr_fire) wr_ptr <= wr_ptr + 1'b1;
            // Output handshake: drop valid when consumer accepts.
            if (out_valid && out_ready) begin
                out_valid <= 1'b0;
            end
            // Refill output skid when it is empty (or being consumed
            // this cycle) and the FIFO has data. rd_ptr advances on the
            // same edge so the next refill reads the next entry.
            if (load_skid) begin
                out_valid <= 1'b1;
                rd_ptr    <= rd_ptr + 1'b1;
            end
        end
    end
    // Memory write split into its own clock-only always block per
    // knowledge/patterns/protected/08_common_bugs.md.
    always @(posedge clk) begin
        if (wr_fire) mem[wr_ptr[ADDR_W-1:0]] <= in_data;
    end
endmodule

module bias_mem #(
    parameter integer SIZE_WORDS    = 256,
    parameter integer WORD_WIDTH    = 8192,
    parameter integer ADDR_W        = 16,
    parameter         MEM_INIT_FILE = "output/weights/bias.mem"
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    output reg  [WORD_WIDTH-1:0]   rd_data,
    input  wire                    rd_en
);
    (* ram_style = "block" *) reg [WORD_WIDTH-1:0] mem [0:SIZE_WORDS-1];
    initial begin
        if (MEM_INIT_FILE != "") $readmemh(MEM_INIT_FILE, mem);
    end
    always @(posedge clk) begin
        if (rd_en) rd_data <= mem[rd_addr];
    end
endmodule

module engine_output_bridge #(
    parameter integer SLOT           = 0,
    parameter integer ACT_W          = 2048,
    parameter integer DATA_W         = 2048,
    parameter integer EXPECTED_BEATS = 1,
    parameter integer NUM_DISPATCHES = 14
) (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              start,                 // sched_engine_output_ready
    input  wire              fifo_out_valid,
    input  wire [ACT_W-1:0]  fifo_out_data,
    output wire              fifo_out_ready,
    input  wire              ready_out,             // downstream consumer's ready_in
    output reg               valid_out,
    output reg  [DATA_W-1:0] data_out,
    output reg               drain_complete         // 1 = this dispatch's beats fully drained
);
    // Serialization geometry. For DATA_W >= ACT_W (no serialization needed)
    // TILES_PER_BEAT collapses to 1; the engine beat is zero-padded into a
    // single consumer tile in the slice expression.
    localparam integer TILES_PER_BEAT = (DATA_W >= ACT_W) ? 1 : (ACT_W / DATA_W);
    localparam integer TILE_IDX_W    = (TILES_PER_BEAT <= 1) ? 1 : $clog2(TILES_PER_BEAT);
    localparam integer EXPECTED_TILES = EXPECTED_BEATS * TILES_PER_BEAT;

    // dispatch_count gates active_slot; ticks once per scheduler 'start' pulse.
    // Width is sized to log2(NUM_DISPATCHES) + 1 headroom bit (max 16 supported
    // here; Fix 14's "+1" cushion catches the final S_NEXT_DISP increment past
    // LAST_DISPATCH).
    // [K5] widened 4->5 bits: 17 dispatches, SLOT up to 16 must not truncate
    // (SLOT[3:0] would alias slot 16 onto slot 0 and corrupt the drain order).
    reg [4:0] dispatch_count;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dispatch_count <= 5'd0;
        else if (start) dispatch_count <= dispatch_count + 5'd1;
    end
    wire active_slot = (dispatch_count == SLOT[4:0]);

    // Beat buffer + tile index. beat_buf holds the current engine beat;
    // tile_idx walks 0..TILES_PER_BEAT-1, emitting one slice per ready cycle.
    reg [ACT_W-1:0]      beat_buf;
    reg                  buf_valid;
    reg [TILE_IDX_W:0]   tile_idx;
    reg [31:0]           tiles_emitted;

    // Tile-slice multiplexer. The +: indexed-part-select picks DATA_W bits
    // starting at tile_idx*DATA_W; for DATA_W>=ACT_W the slice degenerates
    // to "low ACT_W bits with zero-pad above".
    wire [DATA_W-1:0] current_tile;
    generate
        if (DATA_W >= ACT_W) begin : g_pad
            assign current_tile = { {(DATA_W-ACT_W){1'b0}}, beat_buf };
        end else begin : g_slice
            assign current_tile = beat_buf[tile_idx * DATA_W +: DATA_W];
        end
    endgenerate

    // Combinational gates:
    //   emit_ready    : we can send a tile this cycle (buffer has data,
    //                   downstream slot is free, slot is active, not done)
    //   last_tile     : this would be the final tile of the current beat
    //   need_new_beat : next cycle the buffer will be empty
    //   fifo_out_ready: only this slot's active bridge pulls; OR-cascade at
    //                   the wrapper trivially picks the right gate.
    wire emit_ready = active_slot && (!valid_out || ready_out)
                    && !drain_complete && buf_valid;
    wire last_tile  = (tile_idx == (TILES_PER_BEAT[TILE_IDX_W:0] - 1'b1));
    wire need_new_beat = !buf_valid || (emit_ready && last_tile);
    assign fifo_out_ready = active_slot && fifo_out_valid
                          && need_new_beat && !drain_complete;

    // [K1-FDCE] Block A: beat_buf/data_out are stream DATA (sync-only, no
    // reset): beat_buf is consumed (current_tile) only while buf_valid;
    // data_out is sampled downstream only under valid_out -- both controls
    // stay async-reset below. Reset values dead.
    always @(posedge clk) begin
        if (emit_ready) data_out <= current_tile;
        if (fifo_out_ready && fifo_out_valid) beat_buf <= fifo_out_data;
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            valid_out      <= 1'b0;
            buf_valid      <= 1'b0;
            tile_idx       <= {(TILE_IDX_W+1){1'b0}};
            tiles_emitted  <= 32'd0;
            drain_complete <= 1'b0;
        end else begin
            // (1) Consumer accepted current tile — drop valid_out.
            if (valid_out && ready_out) valid_out <= 1'b0;
            // (2) Emit a tile this cycle.
            if (emit_ready) begin
                valid_out     <= 1'b1;
                tiles_emitted <= tiles_emitted + 32'd1;
                if (tiles_emitted + 32'd1 == EXPECTED_TILES[31:0]) begin
                    drain_complete <= 1'b1;
                end
                // Advance tile index OR finish this beat.
                if (last_tile) begin
                    buf_valid <= 1'b0;
                    tile_idx  <= {(TILE_IDX_W+1){1'b0}};
                end else begin
                    tile_idx  <= tile_idx + 1'b1;
                end
            end
            // (3) Pull next beat from FIFO. Placed AFTER the emit block so
            // a simultaneous "emit last tile + load new beat" lands with
            // buf_valid=1 (FIFO load wins the NBA race) and tile_idx=0.
            // ([K1-FDCE] beat_buf data write moved to Block A above.)
            if (fifo_out_ready && fifo_out_valid) begin
                buf_valid <= 1'b1;
                tile_idx  <= {(TILE_IDX_W+1){1'b0}};
            end
            // Single-image: drain_complete latches once and stays. For
            // multi-image inference, a 'clear' input would reset this
            // and tiles_emitted per-frame. Out of scope.
        end
    end
endmodule

`endif // NN2RTL_TOP_NO_STUBS
